{
  "name": "L'Élite Française",
  "description": "A sophisticated French learning app focusing on B1-B2 level dictation, daily vocabulary building (15 words), and advanced sentence construction using Gemini AI.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  DICTATION = 'DICTATION',
  VOCABULARY = 'VOCABULARY',
  SENTENCE_BUILDER = 'SENTENCE_BUILDER',
  TUTOR = 'TUTOR'
}

export interface WordEntry {
  word: string;
  translation: string;
  definition: string;
  example: string;
  type: string; // noun, verb, adj, etc.
}

export interface DictationSession {
  content: string;
  audioData?: string;
  difficulty: 'B1' | 'B2';
}

export interface SentenceChallenge {
  targetSentence: string;
  scrambledWords: string[];
  context: string;
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { WordEntry, DictationSession, SentenceChallenge } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiClient = () => {
  return new GoogleGenAI({ apiKey: API_KEY });
};

// Helper for decoding audio bytes
export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

export const decodeBase64 = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const fetchDailyWords = async (level: string): Promise<WordEntry[]> => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a list of 15 advanced French vocabulary words for level ${level}. Include the translation in Arabic, a definition in French, and an example sentence in French. Respond in JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            word: { type: Type.STRING },
            translation: { type: Type.STRING },
            definition: { type: Type.STRING },
            example: { type: Type.STRING },
            type: { type: Type.STRING },
          },
          required: ["word", "translation", "definition", "example", "type"]
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const fetchDictation = async (level: string): Promise<DictationSession> => {
  const ai = getGeminiClient();

  // 1. Generate the text
  const textResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Write a short, professional paragraph in French (about 40-60 words) suitable for a ${level} level dictation. Use themes like technology, environment, or culture.`,
  });

  const content = textResponse.text.trim();

  // 2. Generate Audio (TTS)
  const audioResponse = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Veuillez lire lentement cette dictée : ${content}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const audioData = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  return {
    content,
    audioData,
    difficulty: level as 'B1' | 'B2'
  };
};

export const fetchSentenceChallenge = async (level: string): Promise<SentenceChallenge> => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Create a sentence formation challenge for level ${level}. Provide a target complex sentence in French, a context in Arabic, and the words scrambled. Respond in JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetSentence: { type: Type.STRING },
          scrambledWords: { type: Type.ARRAY, items: { type: Type.STRING } },
          context: { type: Type.STRING },
        },
        required: ["targetSentence", "scrambledWords", "context"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const checkAnswerWithAI = async (original: string, user: string): Promise<{ score: number, feedback: string }> => {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Compare this original French text with the user's version. 
    Original: "${original}"
    User version: "${user}"
    Provide a score from 0-100 and specific feedback in Arabic about spelling and grammar errors. Respond in JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          feedback: { type: Type.STRING }
        },
        required: ["score", "feedback"]
      }
    }
  });

  return JSON.parse(response.text);
};

