import React, { useState, useEffect } from 'react';
import { fetchDailyWords } from '../services/gemini';
import { WordEntry } from '../types';
import { RefreshCw, BookMarked, Volume2, ChevronRight, ChevronLeft, CheckCircle2 } from 'lucide-react';

const VocabularyView: React.FC = () => {
  const [words, setWords] = useState<WordEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [learnedCount, setLearnedCount] = useState(0);

  useEffect(() => {
    loadWords();
  }, []);

  const loadWords = async () => {
    setLoading(true);
    try {
      const data = await fetchDailyWords('B1-B2');
      setWords(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const nextWord = () => {
    if (currentIndex < words.length - 1) {
      setCurrentIndex(prev => prev + 1);
    }
  };

  const prevWord = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const markLearned = () => {
    if (learnedCount < words.length) {
      setLearnedCount(prev => prev + 1);
      nextWord();
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <RefreshCw className="w-10 h-10 text-blue-500 animate-spin" />
        <p className="text-slate-500 font-medium animate-pulse">Chargement de vos 15 mots du jour...</p>
      </div>
    );
  }

  const current = words[currentIndex];
  const progress = ((currentIndex + 1) / words.length) * 100;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-serif font-bold text-slate-800">Vocabulaire du Jour</h2>
          <p className="text-slate-500">15 nouveaux mots pour enrichir votre français.</p>
        </div>
        <div className="text-right">
          <span className="text-2xl font-bold text-blue-600">{currentIndex + 1}</span>
          <span className="text-slate-400"> / 15</span>
        </div>
      </div>

      <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
        <div 
          className="h-full bg-blue-600 transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      {current && (
        <div className="bg-white rounded-3xl p-8 shadow-xl shadow-slate-200/50 border border-slate-100 min-h-[400px] flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <span className="px-3 py-1 bg-blue-50 text-blue-600 text-xs font-bold rounded-full uppercase tracking-wider">
              {current.type}
            </span>
            <button className="text-slate-300 hover:text-blue-500 transition-colors">
              <BookMarked size={24} />
            </button>
          </div>

          <div className="text-center mb-8">
            <h3 className="text-4xl font-serif font-bold text-slate-900 mb-2">{current.word}</h3>
            <p className="text-2xl text-slate-500 font-medium mb-4">{current.translation}</p>
            <div className="flex justify-center">
              <button className="p-3 bg-slate-100 rounded-full hover:bg-blue-100 text-slate-600 hover:text-blue-600 transition-all">
                <Volume2 size={24} />
              </button>
            </div>
          </div>

          <div className="space-y-6 flex-1">
            <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100">
              <p className="text-xs font-bold text-slate-400 mb-2 uppercase tracking-tight">Définition</p>
              <p className="text-slate-700 leading-relaxed italic">{current.definition}</p>
            </div>

            <div>
              <p className="text-xs font-bold text-slate-400 mb-2 uppercase tracking-tight">Exemple</p>
              <p className="text-slate-800 leading-relaxed font-medium">« {current.example} »</p>
            </div>
          </div>

          <div className="mt-10 flex gap-4">
            <button 
              onClick={prevWord}
              disabled={currentIndex === 0}
              className="p-4 bg-slate-50 text-slate-400 rounded-2xl border border-slate-100 hover:bg-slate-100 disabled:opacity-30 transition-all"
            >
              <ChevronLeft size={24} />
            </button>
            <button 
              onClick={markLearned}
              className="flex-1 bg-green-600 text-white font-bold rounded-2xl py-4 shadow-lg shadow-green-200 hover:bg-green-700 active:scale-95 transition-all flex items-center justify-center gap-2"
            >
              <CheckCircle2 size={20} />
              J'ai appris ce mot
            </button>
            <button 
              onClick={nextWord}
              disabled={currentIndex === words.length - 1}
              className="p-4 bg-slate-50 text-slate-400 rounded-2xl border border-slate-100 hover:bg-slate-100 disabled:opacity-30 transition-all"
            >
              <ChevronRight size={24} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default VocabularyView;

import React, { useState, useRef } from 'react';
import { fetchDictation, checkAnswerWithAI, decodeBase64, decodeAudioData } from '../services/gemini';
import { DictationSession } from '../types';
import { Play, RotateCcw, Send, CheckCircle2, AlertCircle, RefreshCw } from 'lucide-react';

const DictationView: React.FC = () => {
  const [session, setSession] = useState<DictationSession | null>(null);
  const [loading, setLoading] = useState(false);
  const [userInput, setUserInput] = useState('');
  const [result, setResult] = useState<{ score: number, feedback: string } | null>(null);
  const [checking, setChecking] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);

  const startNewDictation = async () => {
    setLoading(true);
    setResult(null);
    setUserInput('');
    try {
      const data = await fetchDictation('B1');
      setSession(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const playAudio = async () => {
    if (!session?.audioData) return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    const ctx = audioContextRef.current;
    const bytes = decodeBase64(session.audioData);
    const buffer = await decodeAudioData(bytes, ctx, 24000, 1);

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start();
  };

  const handleSubmit = async () => {
    if (!session || !userInput.trim()) return;
    setChecking(true);
    try {
      const evaluation = await checkAnswerWithAI(session.content, userInput);
      setResult(evaluation);
    } catch (error) {
      console.error(error);
    } finally {
      setChecking(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-serif font-bold text-slate-800">La Dictée</h2>
          <p className="text-slate-500 italic">Écoutez attentivement et écrivez ce que vous entendez.</p>
        </div>
        {!session && !loading && (
          <button 
            onClick={startNewDictation}
            className="bg-blue-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
          >
            Commencer
          </button>
        )}
      </div>

      {loading && (
        <div className="flex flex-col items-center justify-center min-h-[40vh] gap-4">
          <RefreshCw className="w-10 h-10 text-blue-500 animate-spin" />
          <p className="text-slate-500">Préparation de votre dictée...</p>
        </div>
      )}

      {session && !loading && !result && (
        <div className="bg-white rounded-3xl p-6 shadow-xl border border-slate-100 space-y-6">
          <div className="flex flex-col items-center gap-4 py-8 bg-blue-50 rounded-2xl">
            <button 
              onClick={playAudio}
              className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center text-white shadow-xl hover:scale-105 active:scale-95 transition-all"
            >
              <Play size={32} className="ml-1" />
            </button>
            <p className="text-blue-700 font-bold">Jouer l'audio</p>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-400 uppercase">Votre texte</label>
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              placeholder="Écrivez ici..."
              className="w-full h-48 p-6 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-blue-300 focus:ring-0 text-lg leading-relaxed transition-all outline-none"
            />
          </div>

          <div className="flex gap-4">
            <button 
              onClick={startNewDictation}
              className="flex-1 bg-slate-100 text-slate-600 font-bold py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-200"
            >
              <RotateCcw size={20} /> Autre texte
            </button>
            <button 
              onClick={handleSubmit}
              disabled={checking || !userInput}
              className="flex-[2] bg-blue-600 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 hover:bg-blue-700 shadow-lg shadow-blue-200 disabled:opacity-50"
            >
              {checking ? <RefreshCw className="animate-spin" /> : <Send size={20} />}
              Vérifier ma dictée
            </button>
          </div>
        </div>
      )}

      {result && (
        <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100 space-y-8">
          <div className="text-center">
            <div className={`inline-block p-4 rounded-full mb-4 ${result.score >= 80 ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'}`}>
              {result.score >= 80 ? <CheckCircle2 size={48} /> : <AlertCircle size={48} />}
            </div>
            <h3 className="text-4xl font-serif font-bold text-slate-900 mb-1">Score : {result.score}%</h3>
            <p className="text-slate-500 font-medium">Bon travail ! Voici votre analyse.</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-3">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Texte Original</h4>
              <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 text-slate-800 leading-relaxed font-medium">
                {session?.content}
              </div>
            </div>
            <div className="space-y-3">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Votre Version</h4>
              <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 text-slate-600 leading-relaxed italic">
                {userInput}
              </div>
            </div>
          </div>

          <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100">
            <h4 className="text-blue-800 font-bold mb-2 flex items-center gap-2">
              <MessageSquare className="w-4 h-4" /> ملاحظات المعلم
            </h4>
            <p className="text-blue-900 leading-relaxed text-right" dir="rtl">{result.feedback}</p>
          </div>

          <button 
            onClick={startNewDictation}
            className="w-full bg-blue-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all"
          >
            Nouvelle Dictée
          </button>
        </div>
      )}
    </div>
  );
};

// Helper components for icons not defined in context
const MessageSquare = ({ className, size }: { className?: string, size?: number }) => (
  <svg className={className} width={size || 24} height={size || 24} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
);

export default DictationView;

import React, { useState, useEffect } from 'react';
import { fetchSentenceChallenge, checkAnswerWithAI } from '../services/gemini';
import { SentenceChallenge } from '../types';
import { RefreshCw, CheckCircle2, Trophy, HelpCircle, ArrowRight } from 'lucide-react';

const SentenceBuilderView: React.FC = () => {
  const [challenge, setChallenge] = useState<SentenceChallenge | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedWords, setSelectedWords] = useState<string[]>([]);
  const [availableWords, setAvailableWords] = useState<string[]>([]);
  const [result, setResult] = useState<{ score: number, feedback: string } | null>(null);
  const [checking, setChecking] = useState(false);

  useEffect(() => {
    loadChallenge();
  }, []);

  const loadChallenge = async () => {
    setLoading(true);
    setResult(null);
    setSelectedWords([]);
    try {
      const data = await fetchSentenceChallenge('B2');
      setChallenge(data);
      setAvailableWords(data.scrambledWords);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const selectWord = (word: string, index: number) => {
    setSelectedWords([...selectedWords, word]);
    const newAvailable = [...availableWords];
    newAvailable.splice(index, 1);
    setAvailableWords(newAvailable);
  };

  const deselectWord = (word: string, index: number) => {
    const newSelected = [...selectedWords];
    newSelected.splice(index, 1);
    setSelectedWords(newSelected);
    setAvailableWords([...availableWords, word]);
  };

  const handleVerify = async () => {
    if (!challenge) return;
    setChecking(true);
    try {
      const userSentence = selectedWords.join(' ');
      const evaluation = await checkAnswerWithAI(challenge.targetSentence, userSentence);
      setResult(evaluation);
    } catch (error) {
      console.error(error);
    } finally {
      setChecking(false);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[40vh] gap-4">
        <RefreshCw className="w-10 h-10 text-purple-500 animate-spin" />
        <p className="text-slate-500 font-medium">Construction du défi...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-12">
      <div>
        <h2 className="text-3xl font-serif font-bold text-slate-800">Construction de Phrases</h2>
        <p className="text-slate-500">Formez des structures complexes et élégantes.</p>
