            <p className="text-slate-500 text-sm">Apprendre les 15 nouveaux mots de vocabulaire.</p>
            <div className="mt-4 flex items-center gap-2">
              <div className="h-1.5 flex-1 bg-slate-100 rounded-full overflow-hidden">
                <div className="h-full bg-orange-400 w-1/3"></div>
              </div>
              <span className="text-[10px] font-bold text-slate-400 uppercase">5 / 15</span>
            </div>
          </button>

          <button 
            onClick={() => setActiveView(AppView.DICTATION)}
            className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group text-left"
          >
            <div className="bg-blue-100 text-blue-600 p-3 rounded-2xl w-fit mb-4 group-hover:scale-110 transition-transform">
              <Zap size={24} />
            </div>
            <h4 className="font-bold text-slate-800 text-lg">Dictée Spéciale</h4>
            <p className="text-slate-500 text-sm">Améliorez votre orthographe et écoute active.</p>
            <div className="mt-4">
              <span className="bg-blue-50 text-blue-700 text-[10px] font-bold px-2 py-1 rounded-full uppercase">Prêt</span>
            </div>
          </button>

          <button 
            onClick={() => setActiveView(AppView.SAVED_WORDS)}
            className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group text-left sm:col-span-2 flex items-center gap-6"
          >
            <div className="bg-blue-50 text-blue-600 p-4 rounded-2xl group-hover:scale-110 transition-transform shrink-0">
              <Bookmark size={28} />
            </div>
            <div className="flex-1">
              <h4 className="font-bold text-slate-800 text-lg">Mots Enregistrés</h4>
              <p className="text-slate-500 text-sm">Révisez vos {savedCount} mots favoris sauvegardés pour plus tard.</p>
            </div>
            <div className="bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center font-bold">
              {savedCount}
            </div>
          </button>
        </div>
      </section>

      <section className="bg-slate-900 rounded-[2rem] p-8 text-white">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold">Objectifs de la semaine</h3>
          <Star className="text-yellow-400 fill-yellow-400" size={24} />
        </div>
        <div className="space-y-4">
          {[
            { label: 'Vocabulaire (100 mots)', progress: 65 },
            { label: 'Dictées complétées', progress: 40 },
            { label: 'Phrases construites', progress: 90 },
          ].map((goal, i) => (
            <div key={i} className="space-y-1.5">
              <div className="flex justify-between text-sm font-medium">
                <span className="opacity-80">{goal.label}</span>
                <span className="text-yellow-400">{goal.progress}%</span>
              </div>
              <div className="h-2 bg-white/10 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-400 to-orange-400" 
                  style={{ width: `${goal.progress}%` }}
                ></div>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>(AppView.DASHBOARD);
  const [streak, setStreak] = useState(5);

  const renderView = () => {
    switch (activeView) {
      case AppView.DASHBOARD:
        return <Dashboard setActiveView={setActiveView} />;
      case AppView.VOCABULARY:
        return <VocabularyView />;
      case AppView.DICTATION:
        return <DictationView />;
      case AppView.SENTENCE_BUILDER:
        return <SentenceBuilderView />;
      case AppView.TUTOR:
        return <TutorView />;
      case AppView.SAVED_WORDS:
        return <SavedWordsView onBack={() => setActiveView(AppView.DASHBOARD)} />;
      default:
        return <Dashboard setActiveView={setActiveView} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView} streak={streak}>
      {renderView()}
    </Layout>
  );
};

export default App;
